// ==================================================
//  pages/Orders.jsx — صفحة الطلبات
// ==================================================
import React, { useState, useEffect } from 'react'

const STATUS_MAP = {
  pending:   { label: 'قيد الانتظار', color: '#f39c12', bg: '#fff8e1' },
  confirmed: { label: 'مؤكد',         color: '#3498db', bg: '#e3f2fd' },
  shipped:   { label: 'تم الشحن',     color: '#9b59b6', bg: '#f3e5f5' },
  delivered: { label: 'تم التوصيل',   color: '#27ae60', bg: '#e8f5e9' },
  cancelled: { label: 'ملغي',         color: '#e74c3c', bg: '#fdecea' },
}

// بيانات تجريبية
const SAMPLE_ORDERS = [
  { id: 1, design: { title: 'فستان سهرة ذهبي' }, quantity: 1, total: 450, status: 'delivered', address: 'الرياض، حي النرجس', created_at: '2026-05-01T10:00:00Z' },
  { id: 2, design: { title: 'عباءة كلاسيكية'   }, quantity: 2, total: 760, status: 'shipped',   address: 'جدة، حي الزهراء',   created_at: '2026-05-08T14:00:00Z' },
  { id: 3, design: { title: 'قميص كاجوال'       }, quantity: 1, total: 120, status: 'pending',   address: 'الدمام، حي الفيصلية', created_at: '2026-05-12T09:00:00Z' },
]

export default function Orders() {
  const [orders, setOrders]   = useState([])
  const [loading, setLoading] = useState(true)
  const [filter, setFilter]   = useState('all')

  useEffect(() => {
    // هنا تستدعي getOrders() من orderService
    setTimeout(() => {
      setOrders(SAMPLE_ORDERS)
      setLoading(false)
    }, 600)
  }, [])

  const filtered = filter === 'all' ? orders : orders.filter(o => o.status === filter)

  if (loading) return <div className="page-center"><div className="spinner" /></div>

  return (
    <div style={styles.page}>
      <h1 style={styles.title}>طلباتي</h1>

      {/* فلتر الحالة */}
      <div style={styles.filters}>
        {[['all','الكل'], ['pending','انتظار'], ['shipped','شحن'], ['delivered','مُسلَّم'], ['cancelled','ملغي']].map(([val, label]) => (
          <button
            key={val}
            onClick={() => setFilter(val)}
            className="btn"
            style={{
              ...styles.filterBtn,
              background: filter === val ? '#0a0a0a' : '#fff',
              color:      filter === val ? '#fff'    : '#333',
            }}
          >
            {label}
          </button>
        ))}
      </div>

      {/* قائمة الطلبات */}
      {filtered.length === 0 ? (
        <div style={styles.empty}>
          <span style={{fontSize: 60}}>📦</span>
          <p style={{color:'#aaa', marginTop:12}}>لا توجد طلبات</p>
        </div>
      ) : (
        <div style={styles.list}>
          {filtered.map(order => (
            <OrderCard key={order.id} order={order} />
          ))}
        </div>
      )}

      {/* إجمالي */}
      {orders.length > 0 && (
        <div style={styles.summary}>
          <span style={{color:'#888'}}>إجمالي جميع طلباتي:</span>
          <span style={styles.total}>
            {orders.reduce((sum, o) => sum + o.total, 0)} ر.س
          </span>
        </div>
      )}
    </div>
  )
}

function OrderCard({ order }) {
  const status = STATUS_MAP[order.status] || STATUS_MAP.pending
  const [open, setOpen] = useState(false)

  return (
    <div style={styles.card}>
      <div style={styles.cardHeader}>
        <div>
          <span style={styles.orderId}>طلب #{order.id}</span>
          <h3 style={styles.designName}>{order.design?.title}</h3>
        </div>
        <span style={{ ...styles.badge, color: status.color, background: status.bg }}>
          {status.label}
        </span>
      </div>

      <div style={styles.cardBody}>
        <div style={styles.detail}><span>📅 التاريخ</span>     <span>{new Date(order.created_at).toLocaleDateString('ar-SA')}</span></div>
        <div style={styles.detail}><span>📦 الكمية</span>      <span>{order.quantity} قطعة</span></div>
        <div style={styles.detail}><span>💰 الإجمالي</span>    <span style={{color:'#c9a84c', fontWeight:600}}>{order.total} ر.س</span></div>
        <div style={styles.detail}><span>📍 العنوان</span>     <span style={{maxWidth:220, textAlign:'left'}}>{order.address}</span></div>
      </div>

      {/* خط التتبع */}
      <div style={{marginTop: 20}}>
        <p style={{fontSize:13, color:'#888', marginBottom:12}}>تتبع الطلب:</p>
        <div style={styles.track}>
          {['pending','confirmed','shipped','delivered'].map((s, i) => {
            const steps = ['pending','confirmed','shipped','delivered']
            const currentIdx = steps.indexOf(order.status)
            const done = i <= currentIdx
            return (
              <React.Fragment key={s}>
                <div style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:4 }}>
                  <div style={{ width:28, height:28, borderRadius:'50%', background: done ? '#c9a84c' : '#eee', display:'flex', alignItems:'center', justifyContent:'center', fontSize:13, color: done ? '#fff' : '#aaa' }}>
                    {done ? '✓' : i+1}
                  </div>
                  <span style={{fontSize:10, color: done ? '#c9a84c' : '#aaa'}}>
                    {STATUS_MAP[s]?.label}
                  </span>
                </div>
                {i < 3 && <div style={{flex:1, height:2, background: i < currentIdx ? '#c9a84c' : '#eee', marginBottom:18}} />}
              </React.Fragment>
            )
          })}
        </div>
      </div>
    </div>
  )
}

const styles = {
  page:      { padding: '48px 60px', maxWidth: 860, margin: '0 auto' },
  title:     { fontFamily: "'Playfair Display',serif", fontSize: 40, marginBottom: 32 },
  filters:   { display: 'flex', gap: 10, marginBottom: 32, flexWrap: 'wrap' },
  filterBtn: { padding: '8px 22px', borderRadius: 50, border: '1.5px solid #ddd', cursor: 'pointer', fontSize: 14 },
  list:      { display: 'flex', flexDirection: 'column', gap: 20 },
  card:      { background: '#fff', borderRadius: 20, padding: 28, boxShadow: '0 4px 20px rgba(0,0,0,0.07)' },
  cardHeader:{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 20 },
  orderId:   { fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 },
  designName:{ fontFamily: "'Playfair Display',serif", fontSize: 20 },
  badge:     { padding: '5px 14px', borderRadius: 20, fontSize: 13, fontWeight: 500 },
  cardBody:  { display: 'flex', flexDirection: 'column', gap: 10 },
  detail:    { display: 'flex', justifyContent: 'space-between', fontSize: 14, color: '#555', padding: '6px 0', borderBottom: '1px solid #f5f5f5' },
  track:     { display: 'flex', alignItems: 'center' },
  empty:     { textAlign: 'center', padding: '80px 0' },
  summary:   { marginTop: 32, padding: '20px 28px', background: '#fff', borderRadius: 16, display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 2px 12px rgba(0,0,0,0.05)' },
  total:     { fontFamily: "'Playfair Display',serif", fontSize: 24, color: '#c9a84c', fontWeight: 700 },
}
